SELECT price FROM (SELECT o.price FROM TRANSACTION t 
JOIN ORDERS o ON t.buy_order_no = o.order_no WHERE o.stock_no = #{stockNo} 
ORDER BY t.TRANSACTION_DATE DESC)WHERE ROWNUM = 1

SELECT price-s.prev_price FROM (SELECT o.price FROM TRANSACTION t 
JOIN ORDERS o ON t.buy_order_no = o.order_no WHERE o.stock_no = #{stockNo} 
ORDER BY t.TRANSACTION_DATE DESC), stocks s WHERE ROWNUM = 1 AND s.stock_no = #{stockNo}

SELECT order_no FROM orders 
WHERE content = #{content} AND student_id = #{studentId} AND stock_no = #{stockNo} 
AND state = #{state} AND amount = #{amount} AND price = #{price} ORDER BY order_date DESC
